#include <bits/stdc++.h>
using namespace std;

int n, a[25], m;
char s[100005];
int ans[100005];

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    cin >> m;
    for (int i = 1; i <= m; i++) {
        cin >> s[i];
    }
    for (int i = 1; i <= m; i++) {
        ans[i] = ans[i - 1];
        for (int j = i - 2, k = 1; ; j -= 3, k++) {
            if (j < 1) break;
            if (!(s[j] == 'a' && s[j + 1] == 'b' && s[j + 2] == 'c')) break;
            ans[i] = max(ans[i], ans[j - 1] + a[k]);
            // printf("%d %d %d\n", ans[j - 1], a[k], ans[j - 1] + a[k]);
        }
    }
    cout << ans[m];
    return 0;
}
